import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import LoginModal from './LoginModal';
import logoWhiteImage from '../assets/images/logo1.png';

const Header = ({ onLoginClick }) => {
    const { t, i18n } = useTranslation();
    const [menuOpen, setMenuOpen] = useState(false);
    const [scrolled, setScrolled] = useState(false);
    const [dropdownOpen, setDropdownOpen] = useState('');
    const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);

    const location = useLocation();

    useEffect(() => {
        setMenuOpen(false);
        setDropdownOpen('');
    }, [location]);

    useEffect(() => {
        const handleScroll = () => {
            const isScrolled = window.scrollY > 50;
            if (isScrolled !== scrolled) {
                setScrolled(isScrolled);
            }
        };

        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, [scrolled]);

    const toggleMenu = () => setMenuOpen(!menuOpen);
    const toggleLanguage = () => {
        const newLanguage = i18n.language === 'en' ? 'ja' : 'en';
        i18n.changeLanguage(newLanguage);
    };
    const toggleDropdown = (menu) => setDropdownOpen(dropdownOpen === menu ? '' : menu);
    const handleMouseEnter = (item) => {
        if (item === 'courses' || item === 'about') setDropdownOpen(item);
    };
    const handleMouseLeave = () => setDropdownOpen('');
    const openModal = () => {
        setIsLoginModalOpen(true);
        if (menuOpen) setMenuOpen(false);
    };
    const closeModal = () => setIsLoginModalOpen(false);
    const isActiveLink = (path) => location.pathname === path || location.pathname.startsWith(path + '/');
    const getCurrentLanguage = () => i18n.language === 'en' ? 'EN' : 'JP';

    return (
        <>
            {/* Clean Blur Header */}
            <header className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
                scrolled 
                    ? 'bg-white/90 backdrop-blur-xl border-b border-gray-200/50 shadow-lg' 
                    : 'bg-white/10 backdrop-blur-md'
            }`}>
                <div className="container mx-auto px-6">
                    <div className="flex items-center justify-between h-20">

                        {/* Simple Elegant Logo */}
                        <Link to="/" className="group flex items-center space-x-3">
                            <div className="relative">
                                <div className="w-12 h-12 bg-gradient-to-br from-blue-600 to-purple-600 rounded-xl flex items-center justify-center shadow-lg group-hover:shadow-xl transition-all duration-300">
                                    <img 
                                        src={logoWhiteImage} 
                                        alt="Forum Academy" 
                                        className="h-8 w-auto filter brightness-0 invert" 
                                    />
                                </div>
                            </div>
                            <div className="hidden md:block">
                                <h1 className={`text-xl font-bold transition-colors duration-300 ${
                                    scrolled ? 'text-gray-800' : 'text-white'
                                }`}>
                                    Forum Academy
                                </h1>
                                <p className={`text-sm transition-colors duration-300 ${
                                    scrolled ? 'text-gray-600' : 'text-white/80'
                                }`}>
                                    Excellence in Education
                                </p>
                            </div>
                        </Link>

                        {/* Clean Navigation */}
                        <nav className="hidden lg:flex items-center space-x-8">

                            {/* Programs Dropdown */}
                            <div 
                                className="relative group"
                                onMouseEnter={() => handleMouseEnter('courses')}
                                onMouseLeave={handleMouseLeave}
                            >
                                <button className={`flex items-center space-x-1 py-2 font-medium transition-colors duration-300 ${
                                    scrolled 
                                        ? 'text-gray-700 hover:text-blue-600' 
                                        : 'text-white hover:text-blue-200'
                                } ${isActiveLink('/courses') ? (scrolled ? 'text-blue-600' : 'text-blue-200') : ''}`}>
                                    <span>{t('navigation.programs') || 'Programs'}</span>
                                    <svg className={`w-4 h-4 transition-transform duration-300 ${dropdownOpen === 'courses' ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                                    </svg>
                                </button>

                                {/* Simple Dropdown */}
                                <div className={`absolute top-full left-0 mt-2 w-80 bg-white/95 backdrop-blur-xl rounded-2xl shadow-xl border border-gray-200/50 overflow-hidden transition-all duration-300 ${
                                    dropdownOpen === 'courses' 
                                        ? 'opacity-100 translate-y-0' 
                                        : 'opacity-0 translate-y-2 pointer-events-none'
                                }`}>
                                    <div className="p-6">
                                        <div className="space-y-4">
                                            <h3 className="text-lg font-semibold text-gray-800 mb-4">Our Programs</h3>
                                            {[
                                                { to: '/courses/web-development', icon: '🌐', title: 'Web Development', desc: 'Full-stack development skills' },
                                                { to: '/courses/data-science', icon: '📊', title: 'Data Science', desc: 'Analytics and machine learning' },
                                                { to: '/courses/cybersecurity', icon: '🔒', title: 'Cybersecurity', desc: 'Information security expertise' },
                                                { to: '/courses/ai-ml', icon: '🤖', title: 'AI & Machine Learning', desc: 'Artificial intelligence technologies' }
                                            ].map((course, index) => (
                                                <Link 
                                                    key={index}
                                                    to={course.to} 
                                                    className="group flex items-center space-x-3 p-3 rounded-xl hover:bg-blue-50 transition-all duration-300"
                                                >
                                                    <div className="w-10 h-10 bg-gradient-to-br from-blue-100 to-purple-100 rounded-lg flex items-center justify-center">
                                                        <span className="text-lg">{course.icon}</span>
                                                    </div>
                                                    <div className="flex-1">
                                                        <h4 className="font-medium text-gray-800 group-hover:text-blue-600 transition-colors duration-300">{course.title}</h4>
                                                        <p className="text-sm text-gray-600">{course.desc}</p>
                                                    </div>
                                                </Link>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {/* About Dropdown */}
                            <div 
                                className="relative group"
                                onMouseEnter={() => handleMouseEnter('about')}
                                onMouseLeave={handleMouseLeave}
                            >
                                <button className={`flex items-center space-x-1 py-2 font-medium transition-colors duration-300 ${
                                    scrolled 
                                        ? 'text-gray-700 hover:text-blue-600' 
                                        : 'text-white hover:text-blue-200'
                                } ${isActiveLink('/about') ? (scrolled ? 'text-blue-600' : 'text-blue-200') : ''}`}>
                                    <span>{t('navigation.about') || 'About'}</span>
                                    <svg className={`w-4 h-4 transition-transform duration-300 ${dropdownOpen === 'about' ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                                    </svg>
                                </button>

                                <div className={`absolute top-full left-0 mt-2 w-64 bg-white/95 backdrop-blur-xl rounded-2xl shadow-xl border border-gray-200/50 overflow-hidden transition-all duration-300 ${
                                    dropdownOpen === 'about' 
                                        ? 'opacity-100 translate-y-0' 
                                        : 'opacity-0 translate-y-2 pointer-events-none'
                                }`}>
                                    <div className="p-4">
                                        {[
                                            { to: '/about', icon: 'ℹ️', title: 'About Us' },
                                            { to: '/team', icon: '👥', title: 'Our Team' },
                                            { to: '/partners', icon: '🤝', title: 'Partners' },
                                            { to: '/testimonials', icon: '⭐', title: 'Testimonials' }
                                        ].map((item, index) => (
                                            <Link 
                                                key={index}
                                                to={item.to} 
                                                className="flex items-center space-x-3 p-3 rounded-xl hover:bg-blue-50 transition-all duration-300 group"
                                            >
                                                <span className="text-lg">{item.icon}</span>
                                                <span className="font-medium text-gray-700 group-hover:text-blue-600 transition-colors duration-300">{item.title}</span>
                                            </Link>
                                        ))}
                                    </div>
                                </div>
                            </div>

                            {/* Simple Navigation Links */}
                            {[
                                { to: '/news', title: t('navigation.newsEvents') || 'News' },
                                { to: '/career-services', title: t('navigation.careerServices') || 'Careers' },
                                { to: '/contact', title: t('navigation.contact') || 'Contact' }
                            ].map((item, index) => (
                                <Link 
                                    key={index}
                                    to={item.to} 
                                    className={`py-2 font-medium transition-colors duration-300 ${
                                        scrolled 
                                            ? 'text-gray-700 hover:text-blue-600' 
                                            : 'text-white hover:text-blue-200'
                                    } ${isActiveLink(item.to) ? (scrolled ? 'text-blue-600' : 'text-blue-200') : ''}`}
                                >
                                    {item.title}
                                </Link>
                            ))}
                        </nav>

                        {/* Clean Action Buttons */}
                        <div className="flex items-center space-x-4">

                            {/* Language Toggle */}
                            <button 
                                onClick={toggleLanguage}
                                className={`hidden md:flex items-center space-x-2 px-3 py-2 rounded-lg font-medium transition-all duration-300 ${
                                    scrolled 
                                        ? 'text-gray-700 hover:text-blue-600 hover:bg-blue-50' 
                                        : 'text-white hover:text-blue-200 hover:bg-white/10'
                                }`}
                            >
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 5h12M9 3v2m1.048 9.5A18.022 18.022 0 016.412 9m6.088 9h7M11 21l5-10 5 10M12.751 5C11.783 10.77 8.07 15.61 3 18.129" />
                                </svg>
                                <span>{getCurrentLanguage()}</span>
                            </button>

                            {/* Login Button */}
                            <button 
                                onClick={onLoginClick}
                                className={`hidden md:flex items-center space-x-2 px-4 py-2 rounded-lg font-medium transition-all duration-300 border ${
                                    scrolled 
                                        ? 'text-gray-700 border-gray-300 hover:text-blue-600 hover:border-blue-300 hover:bg-blue-50' 
                                        : 'text-white border-white/30 hover:text-blue-200 hover:bg-white/10'
                                }`}
                            >
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                                </svg>
                                <span>{t('buttons.login') || 'Login'}</span>
                            </button>

                            {/* Apply Button */}
                            <Link 
                                to="/apply" 
                                className="bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white px-6 py-2 rounded-lg font-semibold transition-all duration-300 shadow-lg hover:shadow-xl"
                            >
                                {t('buttons.applyNow') || 'Apply Now'}
                            </Link>

                            {/* Mobile Menu Button */}
                            <button 
                                onClick={toggleMenu}
                                className={`lg:hidden flex flex-col items-center justify-center w-10 h-10 rounded-lg transition-all duration-300 ${
                                    scrolled ? 'text-gray-700' : 'text-white'
                                }`}
                            >
                                <span className={`w-6 h-0.5 bg-current transition-all duration-300 ${menuOpen ? 'rotate-45 translate-y-1.5' : ''}`}></span>
                                <span className={`w-6 h-0.5 bg-current mt-1.5 transition-all duration-300 ${menuOpen ? 'opacity-0' : ''}`}></span>
                                <span className={`w-6 h-0.5 bg-current mt-1.5 transition-all duration-300 ${menuOpen ? '-rotate-45 -translate-y-1.5' : ''}`}></span>
                            </button>
                        </div>
                    </div>

                    {/* Simple Mobile Menu */}
                    <div className={`lg:hidden transition-all duration-500 overflow-hidden ${
                        menuOpen ? 'max-h-96 opacity-100 pb-6' : 'max-h-0 opacity-0'
                    }`}>
                        <div className="space-y-4 pt-6 border-t border-gray-200/30">
                            {[
                                { to: '/courses', title: 'Programs', icon: '🎓' },
                                { to: '/about', title: 'About', icon: 'ℹ️' },
                                { to: '/news', title: 'News', icon: '📰' },
                                { to: '/career-services', title: 'Careers', icon: '💼' },
                                { to: '/contact', title: 'Contact', icon: '📞' }
                            ].map((item, index) => (
                                <Link 
                                    key={index}
                                    to={item.to} 
                                    className={`flex items-center space-x-3 py-3 px-4 rounded-lg transition-all duration-300 ${
                                        scrolled 
                                            ? 'text-gray-700 hover:bg-gray-100' 
                                            : 'text-white hover:bg-white/10'
                                    }`}
                                >
                                    <span className="text-lg">{item.icon}</span>
                                    <span className="font-medium">{item.title}</span>
                                </Link>
                            ))}

                            <div className="pt-4 space-y-3 border-t border-gray-200/30">
                                <button 
                                    onClick={toggleLanguage}
                                    className={`flex items-center space-x-3 w-full py-3 px-4 rounded-lg transition-all duration-300 ${
                                        scrolled 
                                            ? 'text-gray-700 hover:bg-gray-100' 
                                            : 'text-white hover:bg-white/10'
                                    }`}
                                >
                                    <span className="text-lg">🌐</span>
                                    <span className="font-medium">{getCurrentLanguage()} - Switch Language</span>
                                </button>

                                <button 
                                    onClick={onLoginClick}
                                    className={`flex items-center space-x-3 w-full py-3 px-4 rounded-lg transition-all duration-300 ${
                                        scrolled 
                                            ? 'text-gray-700 hover:bg-gray-100' 
                                            : 'text-white hover:bg-white/10'
                                    }`}
                                >
                                    <span className="text-lg">👤</span>
                                    <span className="font-medium">Login</span>
                                </button>

                                <Link 
                                    to="/apply" 
                                    className="block py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white text-center rounded-lg font-semibold shadow-lg"
                                >
                                    Apply Now
                                </Link>
                            </div>
                        </div>
                    </div>
                </div>
            </header>

            <LoginModal 
                isOpen={isLoginModalOpen} 
                onClose={closeModal} 
            />
        </>
    );
};

export default Header;
